// ============================================================
// extension/extension-search.ts
// ============================================================
// The search brain, lifted from components/SemanticFindUI.tsx but
// decoupled from React and from the static demo document. It reuses
// the shared /lib core verbatim:
//
//   substring  ../lib/substring          literal Ctrl+F (chars)
//   keyword    ../lib/minisearch-lexical tokens: exact+prefix+fuzzy
//   semantic   ./embedding-client + ../lib/vector  cosine, OPTIONAL
//   fusion     ../lib/vector (RRF)        rank-position blend + gate
//   tags       ../lib/provenance          Exact / Close / Related / Loose
//
// The one real difference from the demo: semantic is OPTIONAL. If the
// model never loads (CSP, offline, asset missing), search still runs
// on substring + keyword alone — the build doc is explicit that
// embeddings failing must not break find-in-page. When vectors are
// absent we simply omit the semantic list and the cosine gate.
// ============================================================

import { chunkBlocks, hashText, type Chunk, type Block } from "../lib/chunk";
import {
  buildLexicalIndex,
  lexicalSearch,
  type LexicalIndex,
} from "../lib/minisearch-lexical";
import { substringHits, totalOccurrences } from "../lib/substring";
import { classify, type Provenance } from "../lib/provenance";
import { topK, reciprocalRankFusion, type Scored } from "../lib/vector";

// ---- Tuning knobs (mirror the demo / build-doc constants) ----
export const RRF_K = 60;
const SEMANTIC_WEIGHT = 1.0;
const LEXICAL_WEIGHT = 0.9;
const SUBSTRING_WEIGHT = 0.3;
export const LOOSE_FLOOR = 0.15;
export const RELATED_FLOOR = 0.4;
const MAX_RESULTS = 50; // flood guard; user filters by tag below this

export interface SearchResult {
  /** Chunk index (row into the embedding/chunk arrays). */
  index: number;
  /** Fused RRF score — ordering only. */
  score: number;
  /** Raw cosine (0 when semantic is unavailable). */
  cosine: number;
  /** Stemmed doc terms that matched lexically — for highlighting. */
  matchedTerms: string[];
  provenance: Provenance;
  substringCount: number;
}

export interface SearchOutput {
  results: SearchResult[];
  /** Grand total literal occurrences across all chunks (Ctrl+F readout). */
  totalOccurrences: number;
  /** Distinct chunks containing a literal hit. */
  literalChunkCount: number;
  /** Whether the semantic signal contributed to this search. */
  semanticUsed: boolean;
}

/**
 * A page's prepared search state: chunks + the lexical index + the
 * element map, all derived once per page-content hash. Embeddings are
 * attached later (and may stay null forever if the model fails).
 */
export class PageIndex {
  readonly chunks: Chunk[];
  readonly textHash: string;
  private readonly lexical: LexicalIndex;
  private readonly chunkTexts: string[];
  private vectors: Float32Array[] | null = null;

  constructor(blocks: Block[]) {
    this.chunks = chunkBlocks(blocks);
    this.chunkTexts = this.chunks.map((c) => c.text);
    this.textHash = hashText(this.chunkTexts.join("�"));
    this.lexical = buildLexicalIndex(
      this.chunks.map((c) => ({ text: c.text, heading: c.heading }))
    );
  }

  get hasVectors(): boolean {
    return this.vectors !== null && this.vectors.length === this.chunks.length;
  }

  get chunkCount(): number {
    return this.chunks.length;
  }

  setVectors(vectors: Float32Array[]): void {
    if (vectors.length === this.chunks.length) this.vectors = vectors;
  }

  /** Run the full hybrid search for one query. Pure & synchronous —
   *  the query vector (if any) is computed by the caller and passed
   *  in, so this module never imports the model runtime. */
  search(query: string, queryVector: Float32Array | null): SearchOutput {
    const q = query.trim();
    if (!q) {
      return {
        results: [],
        totalOccurrences: 0,
        literalChunkCount: 0,
        semanticUsed: false,
      };
    }

    // --- Signal 1: literal substring (Ctrl+F) ---
    const subHits = substringHits(this.chunkTexts, q);
    const subCountMap = new Map(subHits.map((h) => [h.index, h.count]));
    const subHitSet = new Set(subHits.map((h) => h.index));
    const substringOrder = [...subHits]
      .sort((a, b) => b.count - a.count)
      .map((h) => h.index);

    // --- Signal 2: lexical (exact + prefix + fuzzy) ---
    const lexHits = lexicalSearch(this.lexical, q);
    const lexHitSet = new Set(lexHits.map((h) => h.index));
    const lexTermsMap = new Map(lexHits.map((h) => [h.index, h.terms]));
    const lexExactSet = new Set(lexHits.filter((h) => h.hasExact).map((h) => h.index));
    const lexFuzzySet = new Set(lexHits.filter((h) => h.fuzzyOnly).map((h) => h.index));
    const keywordOrder = lexHits.map((h) => h.index);

    // --- Signal 3: semantic (OPTIONAL) ---
    const semanticUsed = this.hasVectors && queryVector !== null;
    const cosineMap = new Map<number, number>();
    let semanticOrder: number[] = [];
    if (semanticUsed) {
      const sem = topK(queryVector!, this.vectors!, this.vectors!.length);
      for (const s of sem as Scored[]) cosineMap.set(s.index, s.score);
      semanticOrder = (sem as Scored[]).map((s) => s.index);
    }

    // --- Fuse the available lists with weighted RRF ---
    const lists = [
      { name: "keyword", list: { order: keywordOrder, weight: LEXICAL_WEIGHT } },
      { name: "substring", list: { order: substringOrder, weight: SUBSTRING_WEIGHT } },
    ];
    if (semanticUsed) {
      lists.unshift({
        name: "semantic",
        list: { order: semanticOrder, weight: SEMANTIC_WEIGHT },
      });
    }
    const fused = reciprocalRankFusion(lists, this.chunks.length, RRF_K);

    // --- Gate: substring OR keyword OR cosine >= LOOSE_FLOOR ---
    // With no semantic signal the cosine arm is simply never true, so
    // eligibility falls back to literal/keyword — exactly the Ctrl+F
    // promise. Literal matches can never be gated out by low cosine.
    const results: SearchResult[] = fused
      .filter((r) => {
        const cosine = cosineMap.get(r.index) ?? 0;
        return (
          subHitSet.has(r.index) ||
          lexHitSet.has(r.index) ||
          (semanticUsed && cosine >= LOOSE_FLOOR)
        );
      })
      .slice(0, MAX_RESULTS)
      .map((r) => {
        const cosine = cosineMap.get(r.index) ?? 0;
        return {
          index: r.index,
          score: r.score,
          cosine,
          matchedTerms: lexTermsMap.get(r.index) ?? [],
          substringCount: subCountMap.get(r.index) ?? 0,
          provenance: classify(
            {
              hasSubstring: subHitSet.has(r.index),
              hasExactKeyword: lexExactSet.has(r.index),
              hasFuzzyKeyword: lexFuzzySet.has(r.index),
              cosine,
            },
            { relatedFloor: RELATED_FLOOR, looseFloor: LOOSE_FLOOR }
          ),
        };
      });

    return {
      results,
      totalOccurrences: totalOccurrences(subHits),
      literalChunkCount: subHits.length,
      semanticUsed,
    };
  }
}
